// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract FloeLabs is Ownable {
    using SafeMath for uint256;

    struct Loan {
        address borrower;
        address lender;
        uint256 amount;
        uint256 interestRate;
        uint256 duration;
        bool isMatched;
    }

    mapping(uint256 => Loan) public loans;
    uint256 public loanCount;

    event LoanCreated(uint256 indexed loanId, address indexed borrower, uint256 amount, uint256 interestRate, uint256 duration);
    event LoanMatched(uint256 indexed loanId, address indexed lender);
    event LoanSettled(uint256 indexed loanId);

    modifier onlyBot() {
        require(msg.sender == botAddress, "Only bot can call this function");
        _;
    }

    address public botAddress;

    function setBotAddress(address _botAddress) external onlyOwner {
        botAddress = _botAddress;
    }

    function createLoan(uint256 _amount, uint256 _interestRate, uint256 _duration) external {
        require(_amount > 0, "Amount must be greater than zero");
        require(_interestRate > 0, "Interest rate must be greater than zero");
        require(_duration > 0, "Duration must be greater than zero");

        loans[loanCount] = Loan({
            borrower: msg.sender,
            lender: address(0),
            amount: _amount,
            interestRate: _interestRate,
            duration: _duration,
            isMatched: false
        });

        emit LoanCreated(loanCount, msg.sender, _amount, _interestRate, _duration);
        loanCount = loanCount.add(1);
    }

    function matchLoan(uint256 _loanId, address _lender) external onlyBot {
        require(loans[_loanId].isMatched == false, "Loan already matched");
        require(loans[_loanId].borrower != address(0), "Invalid loan ID");

        loans[_loanId].lender = _lender;
        loans[_loanId].isMatched = true;

        emit LoanMatched(_loanId, _lender);
    }

    function settleLoan(uint256 _loanId) external onlyBot {
        require(loans[_loanId].isMatched == true, "Loan not matched");
        require(loans[_loanId].lender != address(0), "Invalid loan ID");

        uint256 totalAmount = loans[_loanId].amount.add(
            loans[_loanId].amount.mul(loans[_loanId].interestRate).div(100)
        );

        (bool success, ) = loans[_loanId].borrower.call{value: totalAmount}("");
        require(success, "Transfer failed");

        emit LoanSettled(_loanId);
    }

    receive() external payable {}
}
