const { expect } = require("chai");
const { ethers } = require("hardhat");

describe("FloeLabs", function () {
    let FloeLabs;
    let floeLabs;
    let owner;
    let borrower;
    let lender;
    let bot;

    beforeEach(async function () {
        FloeLabs = await ethers.getContractFactory("FloeLabs");
        [owner, borrower, lender, bot] = await ethers.getSigners();
        floeLabs = await FloeLabs.deploy();
        await floeLabs.setBotAddress(bot.address);
    });

    it("should create a loan", async function () {
        await floeLabs.connect(borrower).createLoan(100, 5, 30);
        const loan = await floeLabs.loans(0);
        expect(loan.borrower).to.equal(borrower.address);
        expect(loan.amount).to.equal(100);
        expect(loan.interestRate).to.equal(5);
        expect(loan.duration).to.equal(30);
        expect(loan.isMatched).to.equal(false);
    });

    it("should match a loan", async function () {
        await floeLabs.connect(borrower).createLoan(100, 5, 30);
        await floeLabs.connect(bot).matchLoan(0, lender.address);
        const loan = await floeLabs.loans(0);
        expect(loan.lender).to.equal(lender.address);
        expect(loan.isMatched).to.equal(true);
    });

    it("should settle a loan", async function () {
        await floeLabs.connect(borrower).createLoan(100, 5, 30);
        await floeLabs.connect(bot).matchLoan(0, lender.address);
        await floeLabs.connect(bot).settleLoan(0);
        const loan = await floeLabs.loans(0);
        expect(loan.isMatched).to.equal(true);
    });

    it("should revert if non-bot tries to match a loan", async function () {
        await floeLabs.connect(borrower).createLoan(100, 5, 30);
        await expect(floeLabs.connect(borrower).matchLoan(0, lender.address)).to.be.revertedWith("Only bot can call this function");
    });

    it("should revert if non-bot tries to settle a loan", async function () {
        await floeLabs.connect(borrower).createLoan(100, 5, 30);
        await floeLabs.connect(bot).matchLoan(0, lender.address);
        await expect(floeLabs.connect(borrower).settleLoan(0)).to.be.revertedWith("Only bot can call this function");
    });
});
